# -*- coding: utf-8 -*-
"""Tarea 3: Resolucion de Sudoku por backtracking."""

import numpy as np


def leer_matriz(archivo):
    f = open(archivo, "r")
    M = np.zeros((9, 9), dtype=int)
    for i in range(0, 9):
        linea = f.readline()
        b = linea.split()
        for j in range(0, 9):
            M[i, j] = int(b[j])
    return M


def pruebaSudoku(M):
    # Check if placing 'num' at position (i, j) is valid
    def es_valido(i, j, num):
        # Check row
        for col in range(9):
            if M[i, col] == num:
                return False
        # Check column
        for row in range(9):
            if M[row, j] == num:
                return False
        # Check 3x3 box
        start_row = (i // 3) * 3
        start_col = (j // 3) * 3
        for row in range(start_row, start_row + 3):
            for col in range(start_col, start_col + 3):
                if M[row, col] == num:
                    return False
        return True

    # Recursive backtracking
    def backtrack():
        # Find an empty cell (value 0)
        for i in range(9):
            for j in range(9):
                if M[i, j] == 0:
                    # Try numbers 1 through 9
                    for num in range(1, 10):
                        if es_valido(i, j, num):
                            M[i, j] = num
                            if backtrack():
                                return True
                            M[i, j] = 0
                    return False  # No valid number
        return True  # No empty cells left, solved

    backtrack()


if __name__ == "__main__":
    for i in range(1, 8):
        sinSolucion = "data/sudoku" + str(i) + ".txt"
        conSolucion = "data/solsudoku" + str(i) + ".txt"
        A = leer_matriz(sinSolucion)
        print("Probando solucion para " + sinSolucion + ":")
        print(A)
        B = leer_matriz(conSolucion)
        print(" ")
        print("La solucion correcta es:")
        print(B)
        print(" ")
        pruebaSudoku(A)
        print(A == B)
        print(" ")
        assert np.array_equal(A, B)
    print("Su funcion paso todos los tests")
